sql:
SELECT COUNT(DISTINCT up.user_id) AS user_count
FROM user_positions up
WHERE up.unrealized_pnl > 0;

SELECT *
FROM markets
WHERE market_type = 'perp' AND base_asset = 'BTC';

SELECT op.oracle_id, m.market_name, op.oracle_price, op.timestamp, op.source
FROM oracle_prices op
JOIN markets m ON op.market_index = m.market_index;

SELECT SUM(th.base_asset_amount) AS total_trade_amount 
FROM trade_history th 
WHERE th.market_index = 'market_index_value';

external_knowledge:
- 'Open orders' refers to orders that have not been filled or canceled; 
- 'Limit orders' are orders to buy or sell an asset at a specified price or better; 
- 'Market orders' are orders to buy or sell an asset at the current market price; 
- The 'direction' of an order can be either 'long' (buying) or 'short' (selling); 
- 'Leverage' is the ratio of the size of the order to the required margin.

sql:
SELECT user_id, SUM(base_asset_amount) AS total_base_asset_amount
FROM user_positions
GROUP BY user_id;

SELECT MAX(base_asset_amount) AS max_base_asset_amount
FROM orders
WHERE user_id = 1 AND market_index = 'Market_index';
